 37→public class ParameterListWrappingRule :
 38→    StandardRule(
 39→        id = "parameter-list-wrapping",
 40→        usesEditorConfigProperties =
 41→            setOf(
 42→                CODE_STYLE_PROPERTY,
 43→                INDENT_SIZE_PROPERTY,
 44→                INDENT_STYLE_PROPERTY,
 45→                MAX_LINE_LENGTH_PROPERTY,
 46→            ),
 47→    ) {
 48→    private var codeStyle = CODE_STYLE_PROPERTY.defaultValue
 49→    private var indentConfig = IndentConfig.DEFAULT_INDENT_CONFIG
 50→    private var maxLineLength = MAX_LINE_LENGTH_PROPERTY.defaultValue
 51→
 52→    override fun beforeFirstNode(editorConfig: EditorConfig) {
 53→        codeStyle = editorConfig[CODE_STYLE_PROPERTY]
 54→        maxLineLength = editorConfig[MAX_LINE_LENGTH_PROPERTY]
 55→        indentConfig =
 56→            IndentConfig(
 57→                indentStyle = editorConfig[INDENT_STYLE_PROPERTY],
 58→                tabWidth = editorConfig[INDENT_SIZE_PROPERTY],
 59→            )
 60→        if (indentConfig.disabled) {
 61→            stopTraversalOfAST()
 62→        }
 63→    }
 64→
 65→    override fun beforeVisitChildNodes(
 66→        node: ASTNode,
 67→        autoCorrect: Boolean,
 68→        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
 69→    ) {
 70→        when (node.elementType) {
 71→            NULLABLE_TYPE -> wrapNullableType(node, emit, autoCorrect)
 72→            VALUE_PARAMETER_LIST -> {
 73→                if (node.needToWrapParameterList()) {
 74→                    wrapParameterList(node, emit, autoCorrect)
 75→                }
 76→            }
 77→        }
 78→    }
 79→
 80→    private fun wrapNullableType(
 81→        node: ASTNode,
 82→        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
 83→        autoCorrect: Boolean,
 84→    ) {
 85→        require(node.elementType == NULLABLE_TYPE)
 86→        node
 87→            .takeUnless {
 88→                // skip when max line length is not exceedd
 89→                (node.column - 1 + node.textLength) <= maxLineLength
 90→            }?.findChildByType(FUNCTION_TYPE)
 91→            ?.findChildByType(VALUE_PARAMETER_LIST)
 92→            ?.takeIf { it.findChildByType(VALUE_PARAMETER) != null }
 93→            ?.takeUnless { it.textContains('\n') }
 94→            ?.let {
 95→                node
 96→                    .children()
 97→                    .forEach {
 98→                        when (it.elementType) {
 99→                            LPAR -> {
100→                                emit(
101→                                    it.startOffset,
102→                                    "Parameter of nullable type should be on a separate line (unless the type fits on a single line)",
103→                                    true,
104→                                )
105→                                if (autoCorrect) {
106→                                    it.upsertWhitespaceAfterMe("\n${indentConfig.indent}")
107→                                }
108→                            }
109→                            RPAR -> {
110→                                emit(it.startOffset, errorMessage(it), true)
111→                                if (autoCorrect) {
112→                                    it.upsertWhitespaceBeforeMe("\n")
113→                                }
114→                            }
115→                        }
116→                    }
117→            }
118→    }
119→
120→    private fun ASTNode.needToWrapParameterList() =
121→        when {
122→            hasNoParameters() -> false
123→            isPartOfFunctionLiteralInNonKtlintOfficialCodeStyle() -> false
124→            isFunctionTypeWrappedInNullableType() -> false
125→            textContains('\n') -> true
126→            codeStyle == ktlint_official && containsAnnotatedParameter() -> true
127→            exceedsMaxLineLength() -> true
128→            else -> false
129→        }
130→
131→    private fun ASTNode.hasNoParameters(): Boolean {
132→        require(elementType == VALUE_PARAMETER_LIST)
133→        return firstChildNode?.treeNext?.elementType == RPAR
134→    }
135→
136→    private fun ASTNode.isPartOfFunctionLiteralInNonKtlintOfficialCodeStyle(): Boolean {
137→        require(elementType == VALUE_PARAMETER_LIST)
138→        return codeStyle != ktlint_official && treeParent?.elementType == FUNCTION_LITERAL
139→    }
140→
141→    private fun ASTNode.isFunctionTypeWrappedInNullableType(): Boolean {
142→        require(elementType == VALUE_PARAMETER_LIST)
143→        return treeParent.elementType == FUNCTION_TYPE && treeParent?.treeParent?.elementType == NULLABLE_TYPE
144→    }
145→
146→    private fun ASTNode.containsAnnotatedParameter(): Boolean {
147→        require(elementType == VALUE_PARAMETER_LIST)
148→        return this.children()
149→            .filter { it.elementType == VALUE_PARAMETER }
150→            .any { it.isAnnotated() }
151→    }
152→
153→    private fun ASTNode.isAnnotated() =
154→        findChildByType(ElementType.MODIFIER_LIST)
155→            ?.children()
156→            .orEmpty()
157→            .any { it.elementType == ElementType.ANNOTATION_ENTRY }
158→
159→    private fun wrapParameterList(
160→        node: ASTNode,
161→        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
162→        autoCorrect: Boolean,
163→    ) {
164→        val newIndentLevel = getNewIndentLevel(node)
165→        node
166→            .children()
167→            .forEach { child -> wrapParameterInList(newIndentLevel, child, emit, autoCorrect) }
168→    }
169→
170→    private fun getNewIndentLevel(node: ASTNode): Int {
171→        val currentIndentLevel = indentConfig.indentLevelFrom(node.indent(false))
172→        return when {
173→            // IDEA quirk:
174→            // fun <
175→            //     T,
176→            //     R> test(
177→            //     param1: T
178→            //     param2: R
179→            // )
180→            // instead of
181→            // fun <
182→            //     T,
183→            //     R> test(
184→            //         param1: T
185→            //         param2: R
186→            //     )
187→            currentIndentLevel > 0 && node.hasTypeParameterListInFront() -> currentIndentLevel - 1
188→
189→            else -> currentIndentLevel
190→        }
191→    }
192→
193→    private fun wrapParameterInList(
194→        newIndentLevel: Int,
195→        child: ASTNode,
196→        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
197→        autoCorrect: Boolean,
198→    ) {
199→        val indent = "\n" + indentConfig.indent.repeat(newIndentLevel)
200→        when (child.elementType) {
201→            LPAR -> {
202→                val prevLeaf = child.prevLeaf()
203→                if (prevLeaf is PsiWhiteSpace && prevLeaf.textContains('\n')) {
204→                    emit(child.startOffset, errorMessage(child), true)
205→                    if (autoCorrect) {
206→                        prevLeaf.delete()
207→                    }
208→                }
209→            }
210→            VALUE_PARAMETER,
211→            RPAR,
212→            -> {
213→                // aiming for
214→                // ... LPAR
215→                // <line indent + indentSize> VALUE_PARAMETER...
216→                // <line indent> RPAR
217→                val intendedIndent =
218→                    if (child.elementType == VALUE_PARAMETER) {
219→                        indent + indentConfig.indent
220→                    } else {
221→                        indent
222→                    }
223→                val prevLeaf = child.prevLeaf()
224→                if (prevLeaf is PsiWhiteSpace) {
225→                    if (prevLeaf.getText().contains("\n")) {
226→                        // The current child is already wrapped to a new line. Checking and fixing the
227→                        // correct size of the indent is the responsibility of the IndentationRule.
228→                        return
229→                    } else {
230→                        // The current child needs to be wrapped to a newline.
231→                        emit(child.startOffset, errorMessage(child), true)
232→                        if (autoCorrect) {
233→                            // The indentation is purely based on the previous leaf only. Note that in
234→                            // autoCorrect mode the indent rule, if enabled, runs after this rule and
235→                            // determines the final indentation. But if the indent rule is disabled then the
236→                            // indent of this rule is kept.
237→                            (prevLeaf as LeafPsiElement).rawReplaceWithText(intendedIndent)
238→                        }
239→                    }
240→                } else {
241→                    // Insert a new whitespace element in order to wrap the current child to a new line.
242→                    emit(child.startOffset, errorMessage(child), true)
243→                    if (autoCorrect) {
244→                        child.treeParent.addChild(PsiWhiteSpaceImpl(intendedIndent), child)
245→                    }
246→                }
247→                // Indentation of child nodes need to be fixed by the IndentationRule.
248→            }
249→        }
250→    }
251→
252→    private fun ASTNode.exceedsMaxLineLength() = (column - 1 + textLength) > maxLineLength && !textContains('\n')
253→
254→    private fun errorMessage(node: ASTNode) =
255→        when (node.elementType) {
256→            LPAR -> """Unnecessary newline before "(""""
257→            VALUE_PARAMETER ->
258→                "Parameter should start on a newline"
259→            RPAR -> """Missing newline before ")""""
260→            else -> throw UnsupportedOperationException()
261→        }
262→
263→    private fun ASTNode.hasTypeParameterListInFront(): Boolean {
264→        val parent = this.treeParent
265→        val typeParameterList =
266→            if (parent.elementType == PRIMARY_CONSTRUCTOR) {
267→                parent.prevSibling { it.elementType == TYPE_PARAMETER_LIST }
268→            } else {
269→                parent.children().firstOrNull { it.elementType == TYPE_PARAMETER_LIST }
270→            }
271→        val typeListNode =
272→            typeParameterList
273→                ?: parent.psi.collectDescendantsOfType<KtTypeArgumentList>().firstOrNull()?.node
274→                ?: return false
275→        return typeListNode.children().any { it.isWhiteSpaceWithNewline() }
276→    }
277→}
278→
279→public val PARAMETER_LIST_WRAPPING_RULE_ID: RuleId = ParameterListWrappingRule().ruleId
