 21→public fun ASTNode.nextLeaf(
 22→    includeEmpty: Boolean = false,
 23→    skipSubtree: Boolean = false,
 24→): ASTNode? {
 25→    var n = if (skipSubtree) this.lastChildLeafOrSelf().nextLeafAny() else this.nextLeafAny()
 26→    if (!includeEmpty) {
 27→        while (n != null && n.textLength == 0) {
 28→            n = n.nextLeafAny()
 29→        }
 30→    }
 31→    return n
 32→}
