 34→public fun ASTNode.nextLeaf(p: (ASTNode) -> Boolean): ASTNode? {
 35→    var n = this.nextLeafAny()
 36→    while (n != null && !p(n)) {
 37→        n = n.nextLeafAny()
 38→    }
 39→    return n
 40→}
 41→
 42→private fun ASTNode.nextLeafAny(): ASTNode? {
 43→    var n = this
 44→    if (n.firstChildNode != null) {
 45→        do {
 46→            n = n.firstChildNode
 47→        } while (n.firstChildNode != null)
 48→        return n
 49→    }
 50→    return n.nextLeafStrict()
 51→}
 52→
 53→private fun ASTNode.nextLeafStrict(): ASTNode? {
 54→    val nextSibling: ASTNode? = treeNext
 55→    if (nextSibling != null) {
 56→        return nextSibling.firstChildLeafOrSelf()
 57→    }
 58→    return treeParent?.nextLeafStrict()
 59→}
