307→public val ASTNode.column: Int
308→    get() {
309→        var leaf = this.prevLeaf()
310→        var offsetToTheLeft = 0
311→        while (leaf != null) {
312→            if ((leaf.elementType == WHITE_SPACE || leaf.elementType == REGULAR_STRING_PART) && leaf.textContains('\n')) {
313→                offsetToTheLeft += leaf.textLength - 1 - leaf.text.lastIndexOf('\n')
314→                break
315→            }
316→            offsetToTheLeft += leaf.textLength
