import com.pinterest.ktlint.rule.engine.core.api.editorconfig.CODE_STYLE_PROPERTY
import com.pinterest.ktlint.rule.engine.core.api.editorconfig.CodeStyleValue.android_studio
import com.pinterest.ktlint.rule.engine.core.api.editorconfig.CodeStyleValue.intellij_idea
import com.pinterest.ktlint.test.KtLintAssertThat.Companion.assertThatRule
import org.junit.jupiter.api.Test

internal class IndentationRuleLambdaParametersTest {
    private val indentationRuleAssertThat = assertThatRule { IndentationRule() }

    private val correctlyFormattedCode =
        """
        |fun subject() {
        |    combine(
        |        Any(),
        |        Any()
        |    ) { value1,
        |            value2 ->
        |        TODO()
        |    }
        |}
        """.trimMargin()

    private val misalignedLambdaParameters =
        """
        |fun subject() {
        |    combine(
        |        Any(),
        |        Any()
        |    ) { value1,
        |        value2 ->
        |        TODO()
        |    }
        |}
        """.trimMargin()

    @Test
    fun `Given trailing lambda parameters in intellij idea style then parameters align with first parameter`() {
        indentationRuleAssertThat(correctlyFormattedCode)
            .withEditorConfigOverride(CODE_STYLE_PROPERTY to intellij_idea)
            .hasNoLintViolations()
    }

    @Test
    fun `Given trailing lambda parameters in android studio style then parameters align with first parameter`() {
        indentationRuleAssertThat(correctlyFormattedCode)
            .withEditorConfigOverride(CODE_STYLE_PROPERTY to android_studio)
            .hasNoLintViolations()
    }

    @Test
    fun `Given misaligned trailing lambda parameters then formatter aligns them for intellij idea style`() {
        indentationRuleAssertThat(misalignedLambdaParameters)
            .withEditorConfigOverride(CODE_STYLE_PROPERTY to intellij_idea)
            .isFormattedAs(correctlyFormattedCode)
    }
}
"}

